window.DAILY_NEWS_ISSUES["2026-07-01"] = {"id": "tech-2026-07-01", "section_slug": "tech", "publication_name": "我的日报·科技", "issue_date": "2026-07-01", "volume": 1, "number": 8, "date_cn": "2026 年 7 月 1 日 · 周三", "output_path": "issues/2026-07-01.html", "headlines": [{"source_item_ids": ["dbadcb8543a17c7d"], "kicker": "AI芯片 · 推理", "title_zh": "英伟达挑战者Etched估值达50亿美元，AI推理系统订单锁定10亿美元", "summary_zh": "英伟达AI芯片竞争对手Etched周二披露进展：其芯片今年已由台积电成功流片，公司为搭载该芯片的整套系统拿下约10亿美元合同订单，目前正与客户测试首款产品。这类被称为“前沿推理集群”的系统把芯片、定制机架和软件打包，主打让大模型推理更快、更省成本和更省电。Etched成立于2022年，累计融资8亿美元，其中去年12月一轮未公开的5亿美元融资由Stripes领投，投后估值达50亿美元。投资方包括Jane Street、Two Sigma等机构，以及Karpathy、Hinton、李飞飞等AI界知名个人投资人。", "read_body_zh": ["Etched专攻推理环节的专用芯片。推理是用户提交提示词后模型给出回应的过程，也是目前AI公司规模化服务客户时最大的瓶颈和成本中心。公司称，其“前沿推理集群”把自研芯片与定制机架、软件捆绑交付，相比对手在速度、成本和能效上更有优势，首款产品正在客户处测试，尚未大规模交付。", "公司此次以“走出隐身”姿态亮相，但两位创始人Gavin Uberti和Robert Wachen自2024年起已多次对外披露造芯计划，两人均从哈佛退学、成为Thiel学者后创业。据其回忆，2023年即便拿着一份主张AI终将需要专用芯片的30页备忘录，也几乎被所有主要投资人拒绝，公司一度按月发薪、濒临断粮。", "如今融资环境截然不同，投资人正追逐一切与AI相关、尤其能加速推理的芯片技术。竞争对手Cerebras完成了今年首个引人注目的IPO，AI芯片厂商Groq刚募资6.5亿美元；亚马逊、谷歌、微软等云巨头均自研AI芯片，OpenAI也宣布了由博通代工的首款自研芯片。"], "pullquote": null, "ai_impact": "Etched的意义在于验证了“推理专用芯片”这条绕开英伟达通用GPU的商业路径正在跑通：订单先行、台积电已流片，说明客户愿意为更低的单位推理成本买单。这正卡在产业链关键位置——当训练需求趋于集中、推理规模爆发式增长时，谁能压低每次推理的成本与功耗，谁就能在服务大模型的经济账上占优。它与Cerebras、Groq乃至云厂商自研芯片共同构成对英伟达推理市场的合围，长期看会削弱单一供应商的定价权，也让台积电作为共同代工方进一步受益。风险在于产品仍处测试期，能否规模交付、软件生态是否足以承接迁移，仍需观察。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/30/nvidia-competitor-etched-hits-5b-valuation-1b-in-sales-for-ai-chip"}], "relevance_score": 93, "importance_score": 85}, {"source_item_ids": ["cda2d076f633e18b", "2c35ae22493da13c"], "kicker": "大模型 · 发布", "title_zh": "Anthropic发布Claude Sonnet 5：更强agent能力，价格明显低于旗舰", "summary_zh": "Anthropic周二发布中端模型Claude Sonnet 5，主打更强的智能体（agent）能力：能自主制定计划、调用浏览器和终端等工具，并在较少人工监督下长时间运行，性能接近旗舰Opus 4.8但价格更低。发布起该模型即成为免费版和Pro版的默认模型，并在所有订阅档位开放。API采取促销定价，8月31日前为每百万输入token 2美元、每百万输出token 10美元，之后涨至3美元和15美元，整体比Opus 4.8以及OpenAI的GPT-5.5、谷歌Gemini 3.1 Pro便宜。在智能体编码等基准上，Sonnet 5较前代Sonnet 4.6明显提升，在知识类工作上甚至略超Opus 4.8。", "read_body_zh": ["官方称Sonnet 5是迄今最具智能体能力的Sonnet模型，在推理、工具调用、软件编码和知识工作上较2月发布的Sonnet 4.6有实质改进。以一项智能体编码基准为例，Sonnet 5得分63.2%，介于Sonnet 4.6的58.1%与Opus 4.8的69.2%之间；在知识工作基准上则略微超过Opus 4.8。官方定位是：Opus 4.8仍是最高准确度之选，Sonnet 5则以更低价格提供更高质量选项，用户可按需调节投入等级平衡成本与性能。", "多家早期合作方反馈其“完成度”更好。Zapier工程师称把“更新Salesforce客户分级、向企业联系人发布上线公告”这类两步任务交给它，可端到端做完，而过去常在中途卡住；有测试者称它会在未被要求时自行检查输出。这一卖点呼应了OpenAI上周预览的GPT-5.6、谷歌5月的Gemini 3.5 Flash——各家都在把智能体能力作为标配。", "安全方面，官方称Sonnet 5相比前代“不良行为”比例更低，更善于拒绝恶意请求、抵御提示注入攻击，幻觉和迎合性回答也更少；但在错位行为上仍不及更强的Opus 4.8与Claude Mythos预览版。官方还表示未刻意训练其网络安全能力，在开发漏洞利用等危险网安任务上的表现明显弱于Opus级模型。"], "pullquote": null, "ai_impact": "Sonnet 5印证了大模型竞争的分水岭正从“谁的智能体能力最强”转向“谁能更便宜、更可靠地跑智能体”。当agent能力成为各价位的基础标配，差异化就落到单位成本和无人监督下的稳定性上——这也是Anthropic把中端模型定价压到低于自家旗舰和OpenAI、谷歌同档的用意：用性价比抢开发者和默认调用量。促销价到期后近乎翻倍（输出从10美元涨到15美元/百万token），是典型的先用低价换生态、再回收利润的打法，值得关注迁移到它的开发者届时是否留存。对企业而言，“接近旗舰、价格更低”意味着大量自动化工作流可以下沉到更便宜的模型，直接压低AI落地的边际成本。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/30/anthropic-launches-claude-sonnet-5-as-a-cheaper-way-to-run-agents"}, {"name": "Anthropic", "url": "https://www.anthropic.com/news/claude-sonnet-5"}], "relevance_score": 90, "importance_score": 88}, {"source_item_ids": ["85ae8f4911589bba", "56f23c6a00d55813", "06daa384eb474e3e"], "kicker": "AI监管 · 出口管制", "title_zh": "美商务部取消对Anthropic Mythos 5、Fable 5出口管制，模型将恢复全球访问", "summary_zh": "经过数周与特朗普政府谈判，美国商务部取消了对Anthropic旗下Mythos 5和Fable 5两款模型的出口许可要求，Anthropic计划从7月1日（周三）起在自有平台面向全球用户恢复访问，并将陆续在AWS、谷歌云和微软Foundry重新开放，但未给出时间表。这两款被视为迄今最先进的模型，自6月12日被列入出口管制清单后，因无法在规模上合规而一度对公众彻底关闭。商务部长Lutnick称，Anthropic已同意主动检测并处置模型相关安全风险、就相关协议标准与政府协作，并在发现恶意活动时通报政府。", "read_body_zh": ["此次管制源于6月初一份周五晚的最后通牒：出于对模型可能被越狱的担忧，政府发出出口管制指令，禁止任何外国公民（包括企业客户的非美籍成员、乃至Anthropic自己的外籍员工）使用Mythos 5或Fable 5。为在规模上合规几乎不可能，Anthropic只得对公众整体关闭这两款模型。触发管制的越狱由亚马逊研究人员发现，Anthropic称已训练出改进版安全分类器，能在超过99%的情况下拦截该特定手法，被拦截的请求将改由Opus 4.8处理。", "Anthropic同期发布博文，详述其修订后的防护措施与一整套与政府协作的新流程：包括为国家安全相关模型提供“发布前政府访问与评估”、政府可在该阶段接触其技术人员；在发现重大越狱或滥用模式时“快速信息共享”；并联合亚马逊、微软、谷歌等在其Project Glasswing计划中起草评估越狱严重度的通用框架，提出攻击者能力增益、增益广度、武器化难易和可复现性四个维度。", "事件发生在敏感时点：Anthropic正筹备IPO，且已就“供应链风险”认定与政府争执数月。此前商务部先放行Mythos 5给白宫批准的少数机构，OpenAI最新模型也在类似规则下先向获批组织开放。促使政府松绑的背景之一，是Fugu、Tulongfeng等亚洲AI公司开始推出接近Mythos级能力的模型，美国面临确保本国AI保持全球竞争力的压力。"], "pullquote": {"text": "Anthropic已同意主动检测并处置模型相关安全风险、就相关协议标准与政府协作，并在发现恶意活动时通报政府。", "cite": "美国商务部长 Howard Lutnick"}, "ai_impact": "这不是一次普通的政策反复，而是前沿模型分发进入“政府预审”时代的拐点。管制在缺乏公认越狱严重度标准的情况下落地，被不少安全专家质疑更像政治施压而非技术需要；如今解禁的对价，是Anthropic把发布前评估、风险通报、行业共同标准制度化——这实际确立了一条“重大能力模型上线前先过政府和同行这道关”的隐性流程，会外溢到OpenAI等所有前沿实验室。真正促成松绑的是竞争压力：当亚洲模型逼近同级能力，管制反而可能削弱美国AI的全球份额，这说明国家安全与产业竞争力之间的天平正在向后者回摆。对正筹备IPO的Anthropic而言，恢复全球访问既解了营收与增长之困，也把它与政府的关系从对立拉回合作，但政策的高度不确定性仍是悬顶之剑。", "sources": [{"name": "The Verge", "url": "https://www.theverge.com/ai-artificial-intelligence/958964/anthropic-claude-fable-5-is-back"}, {"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/30/trump-drops-restrictions-on-anthropics-mythos-and-fable-models"}, {"name": "Anthropic (via X)", "url": "https://twitter.com/AnthropicAI/status/2072106151890809341"}], "relevance_score": 84, "importance_score": 90}, {"source_item_ids": ["5e5fde5836ede999"], "kicker": "自动驾驶 · 特斯拉", "title_zh": "特斯拉在奥斯汀测试无方向盘无踏板的量产版Cybercab", "summary_zh": "特斯拉已开始在得州奥斯汀测试量产版Cybercab，该车为双座、没有方向盘也没有踏板，目前测试时右侧乘客位仍配有安全监督员。这距其两年前公布Cybercab设计已近两年，此前特斯拉在多城测试的是带方向盘和踏板的原型车，并在部分城市停放了数百辆，引发其将大规模铺开机器人出租车网络的猜测。与此同时，美国国家公路交通安全管理局（NHTSA）上周提出一项拟议规则，将不再要求“专为自动驾驶系统设计的车辆”必须配备制动踏板，目前处于公开征求意见阶段，预计年内落地。", "read_body_zh": ["此次测试标志特斯拉从带人工冗余的原型车迈向真正无人化设计。约一年前，特斯拉已在奥斯汀用Model Y SUV测试Robotaxi服务，期间有时配有安全监督员；近几周它在多个美国城市测试带方向盘踏板的Cybercab原型，并在停车场停放数百辆。金色双座Cybercab上路，会让特斯拉冲刺全国机器人出租车网络的成败都更受瞩目。", "监管门槛正在松动。NHTSA上周披露的拟议规则不再强制“专为自动驾驶系统驾驶的车辆”配备制动踏板，这被视为无方向盘无踏板量产车落地前即将被移除的一道障碍之一，规则仍在公开征求意见期，预计今年晚些时候通过。", "马斯克等高管称有信心超越当前领先者Waymo：特斯拉自造车辆并自研软件，对成本控制更强，而Waymo依赖捷豹、Zeekr等品牌供车；特斯拉还试图仅靠摄像头实现全自动驾驶，Waymo则采用含激光雷达和雷达的更复杂传感器方案。不过特斯拉多年承诺全自动驾驶却尚未规模化部署，奥斯汀车队规模时增时减，且发生过数起轻微事故，其中至少两起由远程操作员导致。"], "pullquote": null, "ai_impact": "Cybercab去掉方向盘和踏板，配合NHTSA拟取消专用自动驾驶车制动踏板要求，意味着技术验证与监管门槛正同步向“无人化专用车”靠拢——这是robotaxi从改装乘用车走向原生设计的关键一步。特斯拉的核心赌注是成本：自造整车加自研软件、仅用摄像头方案，若能跑通，单车与运营成本有望显著低于依赖外部供车和多传感器的Waymo，这正是规模化盈利的胜负手。但纯视觉路线的安全冗余、已发生的（含远程操作员导致的）事故，以及监管仍处征求意见阶段，都是尚未消除的变量。一旦规则落地、无踏板车获准量产，将为整个自动驾驶行业打开专用车设计与生产的合规空间，也把特斯拉多年“画饼”推向必须兑现的节点。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/30/tesla-starts-testing-cybercab-without-pedals-or-a-steering-wheel-in-austin"}], "relevance_score": 82, "importance_score": 83}, {"source_item_ids": ["adcebadc55e98459"], "kicker": "半导体 · 存储", "title_zh": "消息称SK海力士长期供货协议不设价格上限", "summary_zh": "据财联社报道，SK海力士近期与客户签订的长期供应合约（LTA）采用了与竞争对手不同的独特架构——不设价格上限。此举打破了半导体存储器长约的传统定价模式：常规长约会约定价格上限以锁定成本，而不设上限意味着在供不应求、现货价暴涨时，供应商不会因封顶而错失涨价收益。", "read_body_zh": ["长约（LTA，Long-Term Agreement）是供需双方提前锁定较长期供货量与价格的合约。传统存储器长约通常约定价格上限，帮买方封住成本、卖方换取需求确定性；SK海力士此次的做法是保留供货承诺但去掉价格上限。", "据报道，这一架构与竞争对手不同，属于对存储器长约定价惯例的改动。其直接效果是，当市场进入供不应求、现货价大涨的阶段，SK海力士不会因合约封顶而被挡在涨价收益之外，涨价空间可随行就市传导到长约客户。", "该消息目前来自财联社单一来源转述，具体客户、合约期限与定价细节尚未由SK海力士官方确认，仍需后续信息补充核实。"], "pullquote": null, "ai_impact": "长约不设价格上限，是把存储上行周期的涨价红利更多留给供应商的定价结构变化，反映SK海力士在当前HBM/DRAM供不应求格局下议价能力的增强。传统长约用价格上限换供应确定性，如今SK海力士敢去掉上限，说明客户（多为AI服务器和数据中心厂商）对高带宽存储的需求刚性到愿意让渡价格保护、只求锁量。这会放大存储周期上行时的利润弹性，也预示AI带动的存储紧缺可能比以往更持久、更利好上游；对下游而言，则意味着内存成本的不确定性上升，可能顺着服务器、PC等终端向外传导。消息目前为单一来源转述，具体条款仍待确认。", "sources": [{"name": "36氪（财联社）", "url": "https://36kr.com/newsflashes/3876640980070664?f=rss"}], "relevance_score": 91, "importance_score": 78}], "briefs": [{"source_item_ids": ["111e400359e44066"], "title_zh": "亚马逊设立10亿美元FDE组织，跟进OpenAI和Anthropic", "summary_zh": "亚马逊新设一个投入10亿美元的前沿部署工程（FDE）组织，工程师将进驻客户公司内部，帮助部署为其量身打造的AI智能体，重点是快速落地和让客户能自给自足。此举跟随OpenAI和Anthropic此前的类似做法，把AI智能体从平台能力推进到嵌入式交付。（原文因来源限制未取得正文，以上依据官方摘要。）", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/30/amazon-launches-new-1-billion-fde-org-following-openai-and-anthropic"}], "relevance_score": 72, "importance_score": 70}, {"source_item_ids": ["d1058256527a6f65"], "title_zh": "应对AI时代用电激增，韩国拟研究缩短核电站建设周期", "summary_zh": "为满足AI发展带来的庞大用电需求，韩国政府准备研究缩短核电站建设周期以加快扩大电力供应，具体方案将写入即将发布的长期电力供需基本计划。建一座核电站通常需9至10年，政府部门将研究如何压缩工期。韩国目前约三分之一电力来自核能，而拟建的大规模数据中心和半导体产业集群仍需更多稳定电力支撑。", "sources": [{"name": "36氪（财联社）", "url": "https://36kr.com/newsflashes/3876626915406082?f=rss"}], "relevance_score": 78, "importance_score": 75}, {"source_item_ids": ["a79acc2196acf14e"], "title_zh": "松下未来两个财年投约5000亿日元拓展AI基础设施业务", "summary_zh": "松下宣布将在未来两个财年投入约5000亿日元发展AI基础设施相关业务，并力争三年内实现约1.4万亿日元的相关销售额。作为曾经的全球消费电子龙头，松下近年降低对家电业务依赖、并成为特斯拉重要电池供货商，如今借与行业主要企业合作向AI基础设施链条转型。公司同时将裁员规模从此前公布的1万人扩大至1.2万人。", "sources": [{"name": "36氪（新浪财经）", "url": "https://36kr.com/newsflashes/3876636066689287?f=rss"}], "relevance_score": 70, "importance_score": 68}, {"source_item_ids": ["dace02e8c87fd7c2"], "title_zh": "机构：2026年一季度美国PC出货量同比下滑7%，创2023年来最大跌幅", "summary_zh": "Omdia研究显示，2026年一季度美国PC（不含平板）出货量同比下降7.0%至1580万台，为2023年三季度以来最大同比跌幅。下滑主因包括PC内存和存储价格大幅上涨带来的供应受限与成本压力，以及Windows 11升级周期结束后需求提前释放；此外去年同期企业为应对关税预期提前备货造成的高基数，也放大了同比降幅。", "sources": [{"name": "36氪（Omdia）", "url": "https://36kr.com/newsflashes/3876553479352585?f=rss"}], "relevance_score": 68, "importance_score": 64}, {"source_item_ids": ["ebf984e76c332edf"], "title_zh": "开源AI智能体OpenClaw登陆iOS和安卓", "summary_zh": "免费开源AI智能体OpenClaw正式推出iOS和安卓应用。用户可将手机与OpenClaw Gateway配对，这一路由层负责把请求连接到AI智能体及其调用的工具和技能，从而在手机上运行自己的智能体。OpenClaw今年因智能体社交实验MoltBook走红，其创始人Peter Steinberger今年2月宣布加入OpenAI。此次移动端上线把开源智能体从桌面扩展到手机。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/30/openclaw-is-finally-available-on-android-and-ios"}], "relevance_score": 66, "importance_score": 60}, {"source_item_ids": ["7c840892bb345e0b"], "title_zh": "用户反映：安装Cursor iOS应用会不可逆地改动隐私设置", "summary_zh": "一名用户在Hacker News发帖称，安装并登录Cursor的iOS应用后，其账户被从旧版“隐私模式（Legacy，即不存储代码）”切换到措辞更宽松的新版隐私模式，且旧选项从所有菜单中消失、无法恢复。Cursor客服回应称，移动端设置流程中开启Cloud Agents的提示触发了切换，且当前应用内没有切回旧模式的选项，并致歉表示正改进该提示。", "sources": [{"name": "Hacker News", "url": "https://news.ycombinator.com/item?id=48737226"}], "relevance_score": 62, "importance_score": 58}, {"source_item_ids": ["07154c2ff517226b"], "title_zh": "欧洲数字身份钱包依赖谷歌和苹果的远程证明服务", "summary_zh": "多个欧洲国家推行的数字身份钱包依赖谷歌Play Integrity API和苹果Managed Device Attestation这类“远程证明”服务来校验设备未被篡改。批评者指出，Play Integrity会把设备是否运行谷歌授权版安卓、是否经Play商店安装作为判据，等于排斥去谷歌化系统（如GrapheneOS），涉嫌违反《数字市场法》。荷兰、意大利已无条件采用，瑞士则改用安卓硬件证明机制，凸显欧洲把公共数字基础设施建在大平台生态之上的依赖风险。", "sources": [{"name": "Hacker News（Waag）", "url": "https://waag.org/en/article/european-digital-id-wallets-are-gift-google-and-apple"}], "relevance_score": 58, "importance_score": 66}, {"source_item_ids": ["f131fc3041a17a19"], "title_zh": "谷歌发布面向表格数据的零样本基础模型TabFM并开源", "summary_zh": "谷歌推出面向表格数据分类与回归的基础模型TabFM，把此前用于时间序列的“零样本”思路带到表格场景。它将表格预测视为上下文学习问题，用户无需为每个新数据集单独训练、调参或做特征工程，一次前向传播即可对未见过的表格生成预测。模型完全用数亿合成数据集训练，官方称在TabArena基准上优于经精细调参的XGBoost等传统算法，现已在Hugging Face和GitHub开源，并将接入BigQuery，未来可用一条SQL命令完成预测。", "sources": [{"name": "Hacker News（Google Research）", "url": "https://research.google/blog/introducing-tabfm-a-zero-shot-foundation-model-for-tabular-data"}], "relevance_score": 76, "importance_score": 70}, {"source_item_ids": ["5e5852a7465ad77e"], "title_zh": "谷歌NotebookLM新增基于资料生成60秒竖屏短视频功能", "summary_zh": "谷歌NotebookLM新增一种整理笔记的方式：TikTok风格的AI短视频。该功能面向Google AI Ultra和Pro订阅用户推出，可根据用户上传的资料生成60秒竖屏AI短片，配以AI生成的图像与旁白。这是继AI播客、影视化视频、可视化讲解之后又一种消化资料的形式，目前仅支持英文，免费用户将“很快”获得支持。", "sources": [{"name": "The Verge", "url": "https://www.theverge.com/tech/959778/google-notebooklm-ai-clips"}], "relevance_score": 55, "importance_score": 55}, {"source_item_ids": ["23eaf59c6ac75670"], "title_zh": "新研究：恶意网页可诱导AI浏览器绕过安全护栏执行危险操作", "summary_zh": "安全公司LayerX的研究展示了一种新攻击：恶意网站可把AI浏览器诱入一个“规则不再适用”的虚假现实，随后攻击者可让其执行提取私有代码库内容、窃取内置密码管理器凭据等破坏性操作。概念验证中，页面让浏览器去解一个奖励错误答案（如2+2=5）的谜题，一旦模型接受这套设定，就进入护栏失效的“幻想”状态。研究者指出，当前护栏是被动式的、只治标不治本。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/security/2026/06/ai-browsers-can-be-lulled-into-a-dream-world-where-guardrails-no-longer-apply"}], "relevance_score": 74, "importance_score": 72}, {"source_item_ids": ["a38f401174547917"], "title_zh": "谷歌推出更快更便宜的图像生成模型Nano Banana 2 Lite", "summary_zh": "谷歌发布Nano Banana 2 Lite，是其自研图像生成模型的新版本，主打更低延迟与更低成本：可在约4秒内生成图像，价格为每千张0.034美元，适合需要快速大量出图的高频工作流。它取代原Nano Banana（现被称为“旧版模型”），现已在Google AI Studio、Gemini API和企业智能体平台开放。谷歌同日还扩大发布视频模型Gemini Omni Flash并展示电商视频demo。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/30/google-introduces-a-faster-cheaper-image-generator-with-nano-banana-2-lite"}], "relevance_score": 60, "importance_score": 60}, {"source_item_ids": ["cb8e5173ff733bac"], "title_zh": "Anthropic推出Claude Science科研工作台，押注工作流而非新模型", "summary_zh": "Anthropic发布Claude Science，一个面向科研的AI工作台，让科学家在一个环境里完成计算研究，免于在数据库、流程和工具间来回切换。它并非新模型，仍运行现有Claude（含Opus 4.8）：一个主助手作为“项目经理”连接60多个科学数据库、内置基因组学和化学等领域工具，并可派生子助手分工，另有一个专门的事实核查AI在发表前复核引用与计算。产品现向Pro、Max、Team和企业订阅用户开放测试。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/30/anthropics-claude-science-bets-on-workflow-not-a-new-model-to-win-over-scientists"}], "relevance_score": 72, "importance_score": 69}, {"source_item_ids": ["8649003986825390"], "title_zh": "苹果将与Epic的应用商店抽成之争上诉至美国最高法院", "summary_zh": "苹果就与Epic Games的应用商店抽成纠纷向美国最高法院提出上诉，希望推翻此前的藐视法庭裁定。此前法院要求苹果允许开发者在应用内加入指向外部支付的链接，苹果照做却对这类外链收取27%佣金，被第九巡回法院认定违反了原命令“精神”。苹果主张：其他巡回法院只在企业违反命令明确文字时才认定藐视，而涉案命令并未提及佣金。最高法院已确认将审理这一争议。", "sources": [{"name": "Ars Technica", "url": "https://arstechnica.com/tech-policy/2026/06/apple-takes-epic-fight-over-app-store-fees-to-the-supreme-court"}], "relevance_score": 45, "importance_score": 75}, {"source_item_ids": ["4381b2192ce37f1b"], "title_zh": "弗吉尼亚数据中心密集的Henrico县电价大涨25%，政府学校被要求节电", "summary_zh": "弗吉尼亚州Henrico县县长6月26日致信数千名县雇员，请求配合节电：从7月1日起，该县所有政府和学校设施的电价将大涨25%，预计下一财年增加约500万美元成本，且未来数年还会继续上涨。这个约35万人口的县已建有37座数据中心，另有17座在规划中，其中包括拟将数百英亩内战战场改建为数据中心的计划。", "sources": [{"name": "Hacker News（404 Media）", "url": "https://www.404media.co/henrico-virginia-datacenter-energy-cost-email"}], "relevance_score": 76, "importance_score": 70}, {"source_item_ids": ["a7e84b77e9a01a11"], "title_zh": "X推出托管MCP服务器，方便AI工具接入平台实时数据", "summary_zh": "X（原推特）推出托管的MCP（模型上下文协议）服务器，让Claude、Cursor、Grok Build等兼容MCP的AI应用能用用户自己的账户权限直接连接X API。此前开发者需自建并托管MCP服务器、自行处理认证，如今由X托管、用户用自身权限认证即可。该托管MCP不新增能力，仅让搜索、读帖、分析趋势等既有API功能更易被AI应用调用；X明确其不兼容发帖（Write）接口，无法用于自动发帖。", "sources": [{"name": "TechCrunch", "url": "https://techcrunch.com/2026/06/30/x-now-offers-an-mcp-server-to-make-its-platform-easier-for-ai-tools-to-use"}], "relevance_score": 64, "importance_score": 58}], "discarded": [{"source_item_ids": ["857c019ad239f403"], "reason": "偏公司宣传和物理AI概念包装，虽覆盖VLA、世界模型、端侧视觉等主题，但主要服务于一家中国AI公司的产品叙事，缺少足够独立的重大新增事实，且口味档案明确降低此类物理AI营销稿权重。", "relevance_score": 45, "importance_score": 40}, {"source_item_ids": ["33f119a565e583a9"], "reason": "Meta智能眼镜功能限额和订阅争议偏消费者产品收费体验，未命中重点公司和核心技术主题，行业影响有限。", "relevance_score": 25, "importance_score": 35}, {"source_item_ids": ["adb9d21355475950"], "reason": "Wayve员工股份回购主要是创业公司流动性和估值事件，不是自动驾驶技术、监管或商业化拐点，接近‘小公司融资/估值’这类不想看的内容，丢弃。", "relevance_score": 35, "importance_score": 38}], "merged_sources": [{"source_item_ids": ["cda2d076f633e18b", "2c35ae22493da13c"], "reason": "同一事件：Claude Sonnet 5发布，TechCrunch报道与Anthropic官方稿（经Hacker News）合并。"}, {"source_item_ids": ["85ae8f4911589bba", "56f23c6a00d55813", "06daa384eb474e3e"], "reason": "同一事件：美国商务部取消Anthropic Fable 5/Mythos 5出口管制，The Verge、TechCrunch与Anthropic官方X公告合并。"}]};
